begin_text = """
Сделайте глубокий вдох, медленный выдох.
Сконцентрируйтесь на своём вопросе и постарайтесь сформулировать его предельно чётко, в контексте текущей ситуации.
В момент наивысшей ясности сделайте последовательно шесть бросков.
Избегайте торопливости, пусть палец действует самостоятельно, повинуясь внутреннему ритму тела.
"""

button_text = "🪙 Бросить монеты"


def line_symbol(value):
    if value == 1:
        return "━━━━━━"   # ян
    return "━━  ━━"      # инь


def throw_line():
    micro = dt.now().microsecond

    while len(str(micro)) < 6:
        micro = dt.now().microsecond

    digit = int(str(micro)[-1])

    if digit % 2:
        return 1
    return 2


def render_hexagram(lines):
    return "\n".join(line_symbol(line) for line in reversed(lines))


def find_hexagram(lines):
    match = tuple(reversed(lines))

    for number, pattern in iching.items():
        if pattern == match:
            return number, iching_lib[number]

    return None, "Гексаграмма не найдена."


bot = Bot(TOKEN_API)
dp = Dispatcher(bot)

user_lines = {}

kb_throw = ReplyKeyboardMarkup(resize_keyboard=True)
kb_throw.add(KeyboardButton(button_text))

kb_start = ReplyKeyboardMarkup(resize_keyboard=True)
kb_start.add(KeyboardButton("🔮 Вопрос"))


@dp.message_handler(commands=["start"])
async def start_command(message: types.Message):
    await message.answer(
        text="Привет.\n\nНажмите 🔮 Вопрос, чтобы начать.",
        reply_markup=kb_start
    )


@dp.message_handler(
    lambda message:
    message.text == "🔮 Вопрос" or
    message.text == "/question"
)
async def question_command(message: types.Message):
    user_id = message.from_user.id
    user_lines[user_id] = []

    await message.answer(
        text=begin_text,
        reply_markup=kb_throw
    )


@dp.message_handler(lambda message: message.text == button_text or message.text == "/answer")
async def answer_command(message: types.Message):

    user_id = message.from_user.id

    if user_id not in user_lines:
        user_lines[user_id] = []

    lines = user_lines[user_id]

    if len(lines) >= 6:
        lines.clear()

    line = throw_line()
    lines.append(line)

    hexagram_view = render_hexagram(lines)

    if len(lines) < 6:
        await message.answer(
            text=f"Монеты упали.\n\nЛиния {len(lines)} из 6:\n\n{hexagram_view}",
            reply_markup=kb_throw
        )
        return

    number, text = find_hexagram(lines)

    if number:
        final_text = f"Монеты упали.\n\nГексаграмма сложилась:\n\n{hexagram_view}\n\nГексаграмма {number}\n\n{text}"
    else:
        final_text = f"Монеты упали.\n\nГексаграмма сложилась:\n\n{hexagram_view}\n\n{text}"

    lines.clear()

    await message.answer(
        text=final_text,
        reply_markup=kb_start
    )


if __name__ == "__main__":
    executor.start_polling(dp, skip_updates=True)